        assert(err instanceof Error)
        assert(err.message.match(fn))
        done()
      })
    })

    it('should reject the promise with filename in error', (done) => {
      jf.readFile(file)
        .catch(err => {
          assert(err instanceof Error)
          assert(err.message.match(fn))
          done()
        })
    })
  })

